import requests
from bs4 import BeautifulSoup

class PurchaseHistoryScraper:
    def __init__(self, base_url):
        self.base_url = base_url

    def fetch_purchase_history(self, user_id):
        url = f"{self.base_url}/user/{user_id}/purchase-history"
        response = requests.get(url)
        if response.status_code != 200:
            raise Exception("Failed to fetch data")
        return self.parse_purchase_history(response.text)

    def parse_purchase_history(self, html):
        soup = BeautifulSoup(html, 'html.parser')
        purchases = []
        for order in soup.find_all('div', class_='order'):
            order_number = order.find('span', class_='order-number').text
            order_date = order.find('span', class_='order-date').text
            purchases.append({
                'order_number': order_number,
                'order_date': order_date
            })
        return purchases

def solve(base_url, user_id):
    scraper = PurchaseHistoryScraper(base_url)
    return scraper.fetch_purchase_history(user_id)
